# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 1000;
    
    public int baseDamage = 10;
    public int damageUpgradeLevel = 0;
    public int damageUpgradeCost = 50;
    
    public int healthUpgradeLevel = 0;
    public int healthUpgradeCost = 100;
    
    public int currencyUpgradeLevel = 0;
    public int currencyUpgradeCost = 200;
    
    public List<ShopItem> shopItems = new List<ShopItem>();
    
    void Start()
    {
        InitializeShop();
    }
    
    void InitializeShop()
    {
        shopItems.Add(new ShopItem("Health Potion", 50, ItemType.HealthPotion, 25));
        shopItems.Add(new ShopItem("Damage Boost", 100, ItemType.DamageBoost, 1));
        shopItems.Add(new ShopItem("Health Upgrade", 200, ItemType.HealthUpgrade, 1));
        shopItems.Add(new ShopItem("Currency Boost", 150, ItemType.CurrencyBoost, 1));
    }
    
    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }
    
    public bool PurchaseItem(string itemName)
    {
        ShopItem item = shopItems.Find(i => i.name == itemName);
        if (item != null && currency >= item.price)
        {
            currency -= item.price;
            ApplyItemEffect(item);
            return true;
        }
        return false;
    }
    
    public bool UpgradeDamage()
    {
        if (currency >= damageUpgradeCost)
        {
            currency -= damageUpgradeCost;
            damageUpgradeLevel++;
            baseDamage += 5;
            damageUpgradeCost = CalculateUpgradeCost(damageUpgradeLevel, 50);
            return true;
        }
        return false;
    }
    
    public bool UpgradeHealth()
    {
        if (currency >= healthUpgradeCost)
        {
            currency -= healthUpgradeCost;
            healthUpgradeLevel++;
            maxHealth += 20;
            health = maxHealth;
            healthUpgradeCost = CalculateUpgradeCost(healthUpgradeLevel, 100);
            return true;
        }
        return false;
    }
    
    public bool UpgradeCurrency()
    {
        if (currency >= currencyUpgradeCost)
        {
            currency -= currencyUpgradeCost;
            currencyUpgradeLevel++;
            currencyUpgradeCost = CalculateUpgradeCost(currencyUpgradeLevel, 200);
            return true;
        }
        return false;
    }
    
    private void ApplyItemEffect(ShopItem item)
    {
        switch (item.itemType)
        {
            case ItemType.HealthPotion:
                health += item.effectValue;
                if (health > maxHealth) health = maxHealth;
                break;
            case ItemType.DamageBoost:
                baseDamage += item.effectValue;
                break;
            case ItemType.HealthUpgrade:
                maxHealth += item.effectValue;
                health = maxHealth;
                break;
            case ItemType.CurrencyBoost:
                currency += item.effectValue;
                break;
        }
    }
    
    private int CalculateUpgradeCost(int level, int baseCost)
    {
        return baseCost + (level * 25);
    }
    
    public int CalculateDamage()
    {
        return baseDamage + (damageUpgradeLevel * 2);
    }
}

public class ShopItem
{
    public string name;
    public int price;
    public ItemType itemType;
    public int effectValue;
    
    public ShopItem(string name, int price, ItemType itemType, int effectValue)
    {
        this.name = name;
        this.price = price;
        this.itemType = itemType;
        this.effectValue = effectValue;
    }
}

public enum ItemType
{
    HealthPotion,
    DamageBoost,
    HealthUpgrade,
    CurrencyBoost
}